def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    result = []
    start = end = nums[0]

    for i in range(1, len(nums)):
        if nums[i] != nums[i-1]:
            if start == end:
                result.append(str(start))
            else:
                result.append(f"{start}-{end}")
            start = end = nums[i]
        else:
            end = nums[i]

    if start == end:
        result.append(str(start))
    else:
        result.append(f"{start}-{end}")

    return ','.join(result)
